import React, { useEffect, useMemo, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";

// Fallback if nothing is stored yet
const ATL = { name: "Atlanta, GA, USA", lat: 33.7490, lon: -84.3880 };

// LocalStorage keys
const LS_LAST_PLACE = "weatherapp:lastPlace";
const LS_FAVORITES = "weatherapp:favorites";

function isFiniteNum(n) { return typeof n === "number" && isFinite(n); }
function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }
function normLoc(loc) {
  // Ensure valid numbers (and safe ranges) to avoid Leaflet errors
  const lat = isFiniteNum(loc?.lat) ? clamp(loc.lat, -85, 85) : ATL.lat;
  const lon = isFiniteNum(loc?.lon) ? clamp(loc.lon, -180, 180) : ATL.lon;
  const name = typeof loc?.name === "string" && loc.name.trim().length > 0 ? loc.name.trim() : "Unknown";
  return { name, lat, lon };
}
function sameLoc(a, b, eps = 1e-6) {
  if (!a || !b) return false;
  return Math.abs(a.lat - b.lat) <= eps && Math.abs(a.lon - b.lon) <= eps;
}

export default function WeatherApp() {
  // --- Load from localStorage on first mount
  const [place, setPlace] = useState(() => {
    try {
      const raw = localStorage.getItem(LS_LAST_PLACE);
      if (raw) return normLoc(JSON.parse(raw));
    } catch {}
    return ATL;
  });

  const [favorites, setFavorites] = useState(() => {
    try {
      const raw = localStorage.getItem(LS_FAVORITES);
      if (raw) {
        const arr = JSON.parse(raw);
        if (Array.isArray(arr)) {
          return arr
            .map(normLoc)
            // Deduplicate by lat/lon
            .filter((v, i, a) => a.findIndex((x) => sameLoc(x, v)) === i);
        }
      }
    } catch {}
    return [];
  });

  // --- Persist when place/favorites change
  useEffect(() => {
    try {
      localStorage.setItem(LS_LAST_PLACE, JSON.stringify(place));
    } catch {}
  }, [place]);

  useEffect(() => {
    try {
      localStorage.setItem(LS_FAVORITES, JSON.stringify(favorites));
    } catch {}
  }, [favorites]);

  // --- Favorite helpers
  const isFavorite = useMemo(
    () => favorites.some((f) => sameLoc(f, place)),
    [favorites, place]
  );

  function toggleFavorite() {
    setFavorites((prev) => {
      const exists = prev.some((f) => sameLoc(f, place));
      if (exists) return prev.filter((f) => !sameLoc(f, place));
      // Add to front, dedupe by lat/lon
      const next = [place, ...prev];
      return next.filter(
        (v, i, a) => a.findIndex((x) => sameLoc(x, v)) === i
      );
    });
  }

  function selectFavorite(fav) {
    setPlace(normLoc(fav));
    // (Later, trigger backend fetch with fav coords here)
  }

  // --- Handle search selection
  function handleSearchSelect(p) {
    // p: {display, lat, lon, city, state, country}
    const name = p.city
      ? `${p.city}${p.state ? ", " + p.state : ""}, ${p.country}`
      : p.display;
    setPlace(normLoc({ name, lat: p.lat, lon: p.lon }));
    // (Later, trigger backend fetch with p.lat/p.lon here)
  }

  return (
    <div className="relative min-h-screen flex flex-col bg-white overflow-hidden">
      {/* Dynamic background overlays */}
      <WeatherOverlay />

      {/* Top search */}
      <header className="px-4 pt-4">
        <SearchSection
          defaultValue={place?.name || ""}
          onSelect={handleSearchSelect}
        />
      </header>

      {/* Current city + favorite toggle */}
      <section className="px-4 mt-3 mb-2 flex items-center justify-between">
        <div className="text-sm text-gray-700">
          <span className="font-medium text-gray-900">{place?.name}</span>
        </div>
        <button
          type="button"
          onClick={toggleFavorite}
          className={`px-3 py-1.5 rounded-lg text-xs ring-1 transition ${
            isFavorite
              ? "bg-purple-600 text-white ring-purple-500"
              : "bg-black/60 text-white ring-white/10 hover:bg-black/70"
          }`}
          title={isFavorite ? "Remove from favorites" : "Add to favorites"}
        >
          {isFavorite ? "★ Favorited" : "☆ Favorite"}
        </button>
      </section>

      {/* Favorites row (chips) */}
      {favorites.length > 0 && (
        <section className="px-4 mb-3">
          <div className="flex gap-2 overflow-x-auto no-scrollbar py-1">
            {favorites.map((f, idx) => (
              <button
                key={`${f.lat},${f.lon},${idx}`}
                onClick={() => selectFavorite(f)}
                className={`shrink-0 px-3 py-1.5 rounded-xl text-xs ring-1 transition ${
                  sameLoc(f, place)
                    ? "bg-purple-600 text-white ring-purple-500"
                    : "bg-black/60 text-white ring-white/10 hover:bg-black/70"
                }`}
                title={f.name}
              >
                {f.name}
              </button>
            ))}
          </div>
        </section>
      )}

      {/* (Your existing sections: now, tiles, hourly, etc.) */}
      {/* Radar */}
      <section className="px-4 mb-24">
        <Radar
          center={[place?.lat ?? ATL.lat, place?.lon ?? ATL.lon]}
          zoom={6}
          height={320}
          className="rounded-2xl overflow-hidden"
        />
      </section>

      {/* 16‑day / other forecast UI stays the same */}
      <Forecast />

      {/* Bottom bar */}
      <BottomBar />
    </div>
  );
}
